/// Read-model row → API type (Stage 1a worked example). jsonb columns deserialize into the typed
/// structs; `orderable` = ACTIVE_PARTNER + status ACTIVE + acceptance != PAUSED (api.yaml); navigation
/// fields resolve empty until the read resolvers land.
impl From<RestaurantRow> for Restaurant {
    fn from(row: RestaurantRow) -> Self {
        Self {
            id: row.restaurant_id.into(),
            account_id: row.restaurant_account_id.map(Into::into),
            listing_status: row.listing_status.into(),
            orderable: row.listing_status == ds::RestaurantListingStatus::ACTIVE_PARTNER
                && row.status == ds::RestaurantStatus::ACTIVE
                && row.order_acceptance != ds::OrderAcceptanceMode::PAUSED,
            external_identifiers: row
                .external_identifiers
                .and_then(|v| serde_json::from_value(v).ok())
                .unwrap_or_default(),
            slug: row.slug.into(),
            display_name: row.display_name.into(),
            description: row.description,
            tags: row.tags.and_then(|v| serde_json::from_value(v).ok()).unwrap_or_default(),
            cuisine_category: row.cuisine_category.map(Into::into),
            rating: row.rating.map(Into::into),
            reviews_count: row.reviews_count,
            website: row.website.map(Into::into),
            gbp_order_url: row.gbp_order_url.map(Into::into),
            gbp_link_status: row.gbp_link_status.map(Into::into),
            address: serde_json::from_value(row.address).expect("Restaurant.address: invalid jsonb"),
            location: row.location.and_then(|v| serde_json::from_value(v).ok()),
            opening_hours: serde_json::from_value(row.opening_hours).unwrap_or_default(),
            status: row.status.into(),
            order_acceptance: row.order_acceptance.into(),
            default_currency: row.default_currency.into(),
            timezone: row.timezone.map(Into::into),
            preparation_time_minutes: row.preparation_time_minutes,
            updated_at: row.updated_at,
            delivery_jobs: Vec::new(),
            prospects: Vec::new(),
            catalogs: Vec::new(),
            carts: Vec::new(),
            orders: Vec::new(),
        }
    }
}
